import React, { useState } from "react";
import { UrgencyBadge, CategoryBadge, StatusBadge } from "./Badges";
import { fetchMatches, createAssignment } from "../utils/api";
import { getInitials, getAvatarStyle, formatDate } from "../utils/helpers";
import { toast } from "react-toastify";

export default function NeedCard({ need, onStatusChange, showMatchButton = true }) {
  const [matches, setMatches] = useState(null);
  const [loadingMatches, setLoadingMatches] = useState(false);
  const [showMatches, setShowMatches] = useState(false);

  const handleFindMatch = async (e) => {
    e.stopPropagation();
    if (showMatches) { setShowMatches(false); return; }
    try {
      setLoadingMatches(true);
      const res = await fetchMatches(need.id);
      setMatches(res.data.data);
      setShowMatches(true);
    } catch {
      toast.error("Failed to load matches");
    } finally {
      setLoadingMatches(false);
    }
  };

  const handleAssign = async (volunteerId) => {
    try {
      await createAssignment({ volunteerId, needId: need.id });
      toast.success("Volunteer assigned successfully!");
      setShowMatches(false);
      if (onStatusChange) onStatusChange(need.id, "in-progress");
    } catch {
      toast.error("Failed to assign volunteer");
    }
  };

  const handleMarkDone = async (e) => {
    e.stopPropagation();
    try {
      if (onStatusChange) await onStatusChange(need.id, "completed");
      toast.success("Task marked as completed!");
    } catch {
      toast.error("Failed to update status");
    }
  };

  const barColor = need.urgency === "critical" ? "#991b1b" : need.urgency === "high" ? "#dc2626" : need.urgency === "medium" ? "#d97706" : "#16a34a";
  const barWidth = Math.min((need.priorityScore / 20) * 100, 100);

  return (
    <div className="card need-card">
      <div style={{ display: "flex", alignItems: "flex-start", gap: 12 }}>
        <div style={{ minWidth: 52 }}>
          <div style={{ fontSize: 20, fontWeight: 700, color: barColor, fontFamily: "monospace" }}>
            {need.priorityScore}
          </div>
          <div className="priority-bar-wrap">
            <div className="priority-bar" style={{ width: `${barWidth}%`, background: barColor }} />
          </div>
          <div style={{ fontSize: 9, color: "#94a3b8", marginTop: 2 }}>score</div>
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap", marginBottom: 4 }}>
            <span style={{ fontWeight: 600, fontSize: 14 }}>{need.title}</span>
            <UrgencyBadge urgency={need.urgency} />
            <CategoryBadge category={need.category} />
            <StatusBadge status={need.status} />
          </div>
          <p style={{ fontSize: 13, color: "#64748b", marginBottom: 6, lineHeight: 1.4 }}>{need.description}</p>
          <div style={{ display: "flex", gap: 12, fontSize: 11, color: "#94a3b8", fontFamily: "monospace", flexWrap: "wrap" }}>
            <span>👥 {need.peopleAffected} affected</span>
            <span>📍 {need.location?.lat?.toFixed(2)}, {need.location?.lng?.toFixed(2)}</span>
            <span>📅 {formatDate(need.createdAt)}</span>
          </div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 6, flexShrink: 0 }}>
          {need.status === "pending" && showMatchButton && (
            <button className="btn btn-sm btn-primary" onClick={handleFindMatch} disabled={loadingMatches}>
              {loadingMatches ? "..." : showMatches ? "Hide" : "Find Match"}
            </button>
          )}
          {need.status === "in-progress" && (
            <button className="btn btn-sm btn-success" onClick={handleMarkDone}>
              ✓ Done
            </button>
          )}
        </div>
      </div>

      {showMatches && matches && (
        <div style={{ marginTop: 12, borderTop: "1px solid #f1f5f9", paddingTop: 12 }}>
          <div style={{ fontSize: 12, color: "#64748b", marginBottom: 8, fontWeight: 500 }}>
            Top volunteer matches ({matches.length}):
          </div>
          {matches.length === 0 && (
            <p style={{ fontSize: 12, color: "#94a3b8" }}>No available volunteers match this need right now.</p>
          )}
          {matches.slice(0, 4).map((v, i) => {
            const style = getAvatarStyle(i);
            return (
              <div key={v.id} className="match-row">
                <div className="score-circle" style={{
                  background: v.matchScore > 70 ? "#dcfce7" : v.matchScore > 40 ? "#fef9c3" : "#fee2e2",
                  color: v.matchScore > 70 ? "#166534" : v.matchScore > 40 ? "#854d0e" : "#991b1b",
                }}>
                  {v.matchScore}%
                </div>
                <div className="vol-avatar" style={{ width: 32, height: 32, fontSize: 11, background: style.bg, color: style.color }}>
                  {getInitials(v.name)}
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 13, fontWeight: 500 }}>{v.name}</div>
                  <div style={{ display: "flex", gap: 4, flexWrap: "wrap", marginTop: 2 }}>
                    {v.skills.map((s) => (
                      <span key={s} className="skill-tag" style={{
                        color: (v.matchedSkills || []).includes(s) ? "#166534" : "#94a3b8",
                        background: (v.matchedSkills || []).includes(s) ? "#dcfce7" : "#f8fafc",
                      }}>{s}</span>
                    ))}
                  </div>
                </div>
                <div style={{ fontSize: 11, color: "#94a3b8", marginRight: 8, fontFamily: "monospace", textAlign: "right" }}>
                  {v.distance}km
                </div>
                <button className="btn btn-sm btn-primary" onClick={() => handleAssign(v.id)}>
                  Assign
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
